SELECT tblVADeelname.datum_ingevuld, tblVADocument.Naam, tblOpleidingen.code, tblDeelnemers.VolledigeNaam
FROM (tblDeelnemers INNER JOIN (tblDeelname INNER JOIN ((tblVATemplate INNER JOIN tblVADocument ON tblVATemplate.ID = tblVADocument.fkTemplate) INNER JOIN tblVADeelname ON tblVADocument.ID = tblVADeelname.fkVADocument) ON tblDeelname.ID = tblVADeelname.fkDeelname) ON tblDeelnemers.ID = tblDeelname.fkDeelnemer) INNER JOIN tblOpleidingen ON (tblOpleidingen.ID = tblDeelname.fkOpleiding) AND (tblVATemplate.ID = tblOpleidingen.fkVATemplate)
ORDER BY tblVADeelname.datum_ingevuld DESC;

SELECT tblDeelnemers.ID, [Code] & " - " & [Titel] AS Opleiding, tblDeelnemers.VolledigeNaam, tblDeelnemers.Achternaam, UCase([MV]) AS Geslacht, tblDeelnemers.Organisatie, tblDeelnemers.Organisatie2, afdeling,  tblDeelnemers.Adres, tblDeelnemers.Huisnummer, tblDeelnemers.Postcode, tblDeelnemers.Plaats, tblDeelnemers.Email, tblDeelnemers.EmailNotificaties, tblDeelnemers.TelefoonPrive, PriveAdres,PriveHuisNummer, PrivePostcode, PrivePlaats, tblDeelnemers.TelefoonPrivePubliceren, tblDeelnemers.TelefoonWerk, tblDeelnemers.TelefoonWerkPubliceren, tblDeelnemers.TelefoonMobiel, tblDeelnemers.TelefoonMobielPubliceren
FROM tblOpleidingen INNER JOIN (tblDeelnemers INNER JOIN tblDeelname ON tblDeelnemers.ID = tblDeelname.fkDeelnemer) ON tblOpleidingen.ID = tblDeelname.fkOpleiding
ORDER BY [Code] & " - " & [Titel],tblDeelnemers.Achternaam;

SELECT  tblDeelnemers.ID, tblDeelnemers.VolledigeNaam, tblDeelnemers.Achternaam, tblDeelnemers.MV, tblDeelnemers.Email, tblDeelnemers.EmailNotificaties, tblDeelnemers.EmailForumNotificaties, tblDeelnemers.EmailNieuwsNotificaties
FROM tblDeelnemers
ORDER BY tblDeelnemers.Achternaam;

SELECT tblDocenten.ID, tblDocenten.VolledigeNaam, tblDocenten.Achternaam, tblDocenten.MV, tblDocenten.Email, tblDocenten.EmailNotificaties, tblDocenten.EmailForumNotificaties, tblDocenten.EmailNieuwsNotificaties
FROM tblDocenten
ORDER BY tblDocenten.Achternaam;

SELECT  tblPraktijkopleiders.ID, tblPraktijkopleiders.VolledigeNaam, tblPraktijkopleiders.Achternaam, tblPraktijkopleiders.MV, tblPraktijkopleiders.Email, tblPraktijkopleiders.EmailNotificaties, tblPraktijkopleiders.EmailForumNotificaties, tblPraktijkopleiders.EmailNieuwsNotificaties
FROM tblPraktijkopleiders
ORDER BY tblPraktijkopleiders.Achternaam;

SELECT DISTINCT tblPOinstellingen.Naam, tblPOinstellingen.Plaats, tblSRHForumLeden.volledigenaam, tblLogins.Roepnaam, tblSRHForumLeden.Achternaam, tblSRHForumLeden.MV, tblInventarisatiePersonenPerOrg.email, tblDifferentiatie.CODE AS Opl, tblBIGDifferentiatie.Code AS Diff 
FROM (tblSRHForumLeden INNER JOIN ((tblPOinstellingen INNER JOIN (tblDifferentiatie RIGHT JOIN (tblBIGDifferentiatie RIGHT JOIN tblOpleidingsplaatsen ON tblBIGDifferentiatie.ID = tblOpleidingsplaatsen.fkBIGDifferentiatie) ON tblDifferentiatie.ID = tblOpleidingsplaatsen.fkDifferentiatie) ON tblPOinstellingen.ID = tblOpleidingsplaatsen.fkPOInstelling) INNER JOIN tblInventarisatiePersonenPerOrg ON tblPOinstellingen.ID = tblInventarisatiePersonenPerOrg.fkPOInstelling) ON tblSRHForumLeden.ID = tblInventarisatiePersonenPerOrg.fkPersoon) INNER JOIN tblLogins ON tblSRHForumLeden.ID = tblLogins.fkSRHForumLid
WHERE (((tblOpleidingsplaatsen.Jaar)=Year(Date())+1) AND ((tblOpleidingsplaatsen.saldoplaatsen)>0) and tblOpleidingsplaatsen.bactueel=true);

SELECT tblDeelname.id, tblOpleidingen_1.code AS HoortBij, tblDeelnemers.VolledigeNaam, tblOpleidingen.code AS Keuzemodule, tblOpleidingen_1.BNSOpleiding
FROM tblDeelnemers INNER JOIN ((tblOpleidingen AS tblOpleidingen_1 INNER JOIN tblDeelname AS tblDeelname_1 ON tblOpleidingen_1.ID = tblDeelname_1.fkOpleiding) INNER JOIN (tblOpleidingen INNER JOIN tblDeelname ON tblOpleidingen.ID = tblDeelname.fkOpleiding) ON tblDeelname_1.ID = tblDeelname.fkHoofddeelname) ON tblDeelnemers.ID = tblDeelname.fkDeelnemer
WHERE (((tblOpleidingen_1.BNSOpleiding)=True));

SELECT tblopleidingen.id, tblOpleidingen.code, tblOpleidingen.datOnSite, tblOpleidingen.titel
FROM tblOpleidingen
WHERE (((tblOpleidingen.[datOnSite])<=Date()) AND ((tblOpleidingen.[id]) Not In (select fkopleiding from tblDeelname where einddatum is null or einddatum>date())));

SELECT tblP_Praktijkopleiders.VolledigeNaam as Popleider, tblPraktijkOpleiders.VolledigeNaam as Praktijkopleider
FROM tblP_Praktijkopleiders INNER JOIN tblPraktijkOpleiders ON tblP_Praktijkopleiders.ID = tblPraktijkOpleiders.fkPOpleider
ORDER BY tblP_Praktijkopleiders.Achternaam, tblPraktijkOpleiders.Achternaam;

SELECT tblDocenten.VolledigeNaam
FROM tblDocenten INNER JOIN tblLogins ON tblDocenten.ID = tblLogins.fkDocent
WHERE (((tblLogins.blnFotoGewijzigd)=True));

SELECT tblAgenda.fkOpleiding, [code] & "- " & [titel] AS opleiding_omschr, tblAgenda.volgnummer, tblAgenda.Datum, tblAgenda.Omschrijving, Left(tblAgenda.Tijd & "",5) AS StartTijd, Left(tblAgenda.EindTijd & "",5) AS EindTijd, tblDocenten.AchterNaam as AchternaamDocent, tblDocenten.VolledigeNaam AS Docent, IIf(Not IsNull([Tekstdraaiboek]) Or Not IsNull([download]),'Ja','Nee') AS Draaiboek, tblDraaiboek.fkOpleiding, ( hour(EindTijd) + (minute(EindTijd)/60) ) - ( hour(Tijd)  + (minute(Tijd)/60))  as Uren
FROM tblOpleidingen INNER JOIN (tblDraaiboek RIGHT JOIN (tblDocenten RIGHT JOIN (tblAgenda LEFT JOIN tblDocentenPerAgendapunt ON tblAgenda.ID = tblDocentenPerAgendapunt.fkAgenda) ON tblDocenten.ID = tblDocentenPerAgendapunt.fkDocent) ON tblDraaiboek.ID = tblAgenda.fkDraaiboek) ON tblOpleidingen.ID = tblAgenda.fkOpleiding
ORDER BY tblOpleidingen.Code, tblOpleidingen.Titel, tblAgenda.volgnummer;

SELECT tblModuleVoorkeuren.id,  tblOpleidingen.code, tblDeelnemers.VolledigeNaam, tblModuleVoorkeuren.datestamp, tblModuleVoorkeuren.voorkeur1, tblModuleVoorkeuren.voorkeur2, tblModuleVoorkeuren.voorkeur3, tblModuleVoorkeuren.voorkeur4, tblModuleVoorkeuren.voorkeur5
FROM tblOpleidingen INNER JOIN (tblDeelnemers INNER JOIN tblModuleVoorkeuren ON tblDeelnemers.ID = tblModuleVoorkeuren.fkDeelnemer) ON tblOpleidingen.ID = tblModuleVoorkeuren.fkOpleiding
ORDER BY tblOpleidingen.code, tblDeelnemers.Achternaam;
